 78→    public void enableNodeRoleIfNotExist(Long userId, String spaceId, Long spaceNodeId, boolean includeExtend) {
 79→        if (controlService.existsByControlId(spaceNodeId.toString())) {
 80→            log.info("Node role already exists, spaceId: {}, spaceNodeId: {}",spaceId, spaceNodeId);
 81→            return;
 82→        }
 83→
 84→        if (includeExtend) {
 85→            // copy parent roles to this node
 86→            Map<String, Set<Long>> roleToUnitIds = getParentRoleToUnitIds(spaceId, spaceNodeId);
 87→            roleToUnitIds.forEach((role, unitIds) ->
 88→                    controlRoleService.saveOrUpdateControlRole(userId, spaceNodeId.toString(), new ArrayList<>(unitIds), role));
 89→        }
 90→        controlService.create(userId, spaceId, spaceNodeId.toString(), ControlType.SPACE_NODE);
 91→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, null, null);
 92→    }
