 94→    @Override
 95→    public void disableNodeRole(String spaceId, Long spaceNodeId) {
 96→        controlService.removeControl(List.of(spaceNodeId.toString()));
 97→        controlRoleService.removeControl(List.of(spaceNodeId.toString()));
 98→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, null, null);
 99→    }
