107→    private Map<String, Set<Long>> getParentRoleToUnitIds(String spaceId, Long spaceNodeId) {
108→        Long parentNodeId = nodeRoleQueryManager.getNodeExtendNodeId(spaceNodeId);
109→        List<ControlRoleEntity> controlRoleUnits;
110→        if (parentNodeId == null) {
111→            // No parent node has enabled permissions, default workbench role, load root department information
112→            Long rootTeamUnitId = apitableGrpcClientService.getRootTeamUnitId(spaceId);
113→            ControlRoleEntity defaultRoleUnit = ControlRoleEntity.builder()
114→                    .roleCode(SpaceNode.DEFAULT_ROLE)
115→                    .unitId(rootTeamUnitId)
