 72→    @Override
 73→    @Transactional
 74→    public void addNodeRole(Long userId, String spaceId, Long spaceNodeId, String role, List<Long> unitIds) {
 75→        log.info("[1822-PermApply] addNodeRole spaceNodeId={} role={} unitIds={} userId={}", spaceNodeId, role, unitIds, userId);
 76→        spaceNodeService.checkSpaceNodeExist(spaceNodeId);
 77→        enableNodeRoleIfNotExist(userId, spaceId, spaceNodeId, true);
 78→        controlRoleService.saveOrUpdateControlRole(userId, spaceNodeId.toString(), unitIds, role);
 79→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, unitIds, role);
 80→        log.info("[1822-PermApply] addNodeRole done spaceNodeId={} role={} unitIds={}", spaceNodeId, role, unitIds);
 81→        // 记录权限变更日志
 82→        logPermissionChange(userId, spaceId, spaceNodeId, unitIds, "set", null, role);
