 85→    @Override
 86→    @Transactional
 87→    public EditRoleResultVo updateNodeRole(Long userId, String spaceId, Long spaceNodeId, String role, List<Long> unitIds) {
 88→        spaceNodeService.checkSpaceNodeExist(spaceNodeId);
 89→        enableNodeRoleIfNotExist(userId, spaceId, spaceNodeId, false);
 90→
 91→        // 记录旧角色用于日志
 92→        List<ControlRoleEntity> oldRoles = controlRoleService.getByControlIdAndUnitIds(spaceNodeId.toString(), unitIds);
 93→        Map<Long, String> oldRoleMap = oldRoles.stream()
 94→                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
 95→
 96→        controlRoleService.saveOrUpdateControlRole(userId, spaceNodeId.toString(), unitIds, role);
 97→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, unitIds, role);
 98→
 99→        // 记录权限变更日志
100→        logPermissionChangeWithOldRoles(userId, spaceId, spaceNodeId, unitIds, role, oldRoleMap);
101→
102→        // 权限冲突校验
103→        return checkMemberTeamConflict(spaceId, spaceNodeId, role, unitIds);
104→    }
