136→                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
137→
138→        controlRoleService.removeByControlIdAndUnitIds(spaceNodeId.toString(), unitIds);
139→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, unitIds, null);
140→
141→        // 记录权限变更日志
142→        Long userId = SessionContext.getUserId();
143→        logPermissionRemove(userId, spaceId, spaceNodeId, unitIds, oldRoleMap);
144→    }
