146→    private Map<String, Set<Long>> getParentRoleToUnitIds(String spaceId, Long spaceNodeId) {
147→        Long parentNodeId = nodeRoleQueryManager.getNodeExtendNodeId(spaceNodeId);
148→        List<ControlRoleEntity> controlRoleUnits;
149→        if (parentNodeId == null) {
150→            // No parent node has enabled permissions, default workbench role, load root department information
151→            Long rootTeamUnitId = apitableGrpcClientService.getRootTeamUnitId(spaceId);
152→            ControlRoleEntity defaultRoleUnit = ControlRoleEntity.builder()
153→                    .roleCode(SpaceNode.DEFAULT_ROLE)
154→                    .unitId(rootTeamUnitId)
155→                    .build();
156→
157→            controlRoleUnits = List.of(defaultRoleUnit);
158→        } else {
159→            // load parent node role
160→            controlRoleUnits =
161→                    controlRoleService.getByControlId(parentNodeId.toString());
162→        }
163→        return controlRoleUnits.stream()
164→                .collect(groupingBy(ControlRoleEntity::getRoleCode,
165→                        mapping(ControlRoleEntity::getUnitId, toSet())));
166→    }
