184→    /**
185→     * 权限冲突校验：检查成员所在小组权限是否高于成员本身被设置的权限
186→     */
187→    private EditRoleResultVo checkMemberTeamConflict(String spaceId, Long spaceNodeId, String newRole, List<Long> unitIds) {
188→        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
189→        List<NodeRoleUnit> memberUnits = unitInfos.stream()
190→                .filter(u -> u.getUnitType() != null && u.getUnitType() == 3)
191→                .toList();
192→
193→        if (memberUnits.isEmpty()) {
194→            return EditRoleResultVo.noConflict();
195→        }
196→
197→        NodeRoleLevel newLevel = NodeRoleLevel.fromRoleTag(newRole);
198→
199→        for (NodeRoleUnit memberUnit : memberUnits) {
200→            Long memberUserId = memberUnit.getUnitRefId();
201→            List<Long> memberAllUnitIds = apitableGrpcClientService.getUnitsByMember(memberUserId, spaceId);
202→
203→            if (CollectionUtils.isEmpty(memberAllUnitIds)) continue;
204→            List<ControlRoleEntity> teamRoles = controlRoleService.getByControlIdAndUnitIds(spaceNodeId.toString(), memberAllUnitIds);
205→
206→            for (ControlRoleEntity teamRole : teamRoles) {
207→                if (unitIds.contains(teamRole.getUnitId())) continue;
208→                NodeRoleLevel teamLevel = NodeRoleLevel.fromRoleTag(teamRole.getRoleCode());
209→                if (teamLevel.getLevel() > newLevel.getLevel()) {
210→                    List<NodeRoleUnit> teamInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, List.of(teamRole.getUnitId()));
211→                    String teamName = CollectionUtils.isNotEmpty(teamInfos) ? teamInfos.getFirst().getUnitName() : "未知小组";
212→                    String teamRoleDisplay = ROLE_DISPLAY_MAP.getOrDefault(teamRole.getRoleCode(), teamRole.getRoleCode());
213→
214→                    return EditRoleResultVo.builder()
215→                            .hasConflict(true)
216→                            .conflictTeamName(teamName)
217→                            .conflictTeamRole(teamRole.getRoleCode())
218→                            .conflictMessage("因为用户所处的组对文档有" + teamRoleDisplay + "权限，所以本次操作后用户依旧对文档有"
219→                                    + teamRoleDisplay + "权限，如果想要彻底改变用户权限，请将用户移出所在组，或改变其所在组权限")
220→                            .build();
221→                }
222→            }
223→        }
224→        return EditRoleResultVo.noConflict();
225→    }
