230→        String operatorName = getOperatorName(userId, spaceId);
231→        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
232→        for (NodeRoleUnit unit : unitInfos) {
